SELECT u.*, d.dept_name, IFNULL(r.role_name, '') AS role_name FROM user u LEFT JOIN dept d ON u.dept_id = d.dept_id LEFT JOIN user_role ur ON u.user_id = ur.user_id LEFT JOIN role r ON ur.role_id = r.role_id WHERE 1=1
AND u.dept_id IN
#{id}
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.status = #{status}
GROUP BY u.user_id ORDER BY u.create_time LIMIT #{offset}, #{pageSize}

SELECT COUNT(DISTINCT u.user_id) FROM user u LEFT JOIN dept d ON u.dept_id = d.dept_id LEFT JOIN user_role ur ON u.user_id = ur.user_id LEFT JOIN role r ON ur.role_id = r.role_id WHERE 1=1
AND u.dept_id IN
#{id}
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.status = #{status}

